select distinct Chain_ct , idf_ct
from BEST..TI17FNC 
where IDF_CT in (select distinct IDF_CT from BEST..TI17REQFNC where IDF_CT not like '%INI%' and (REQCOD_CT like 'I17L%POS' or REQCOD_CT like 'I17P%POS') )
*/

delete BEST..TI17REQFNC where REQCOD_CT like "I17[LP][QY]POSX" 

 
 
 
 
 
